function lengthTypeFor(reading: string, explicit?: PracticeTextLengthType): PracticeTextLengthType {
  if (explicit) return explicit;
  const keyCount = getPrimaryRomanization(reading).length;
  if (keyCount <= 12) return 'word';
  if (keyCount <= 32) return 'short';
  return 'medium';
}

function difficultyFor(category: PracticeTextCategory, lengthType: PracticeTextLengthType, difficult: boolean): PracticeTextDifficulty {
  if (category === 'programming' || category === 'internet') return difficult ? 'technical' : 'normal';
  if (lengthType === 'word') return difficult ? 'normal' : 'beginner';
  if (lengthType === 'short') return difficult ? 'advanced' : 'beginner';
  if (lengthType === 'long') return difficult ? 'advanced' : 'normal';
  return difficult ? 'advanced' : 'normal';
}

function tagsFor(category: PracticeTextCategory, lengthType: PracticeTextLengthType, difficulty: PracticeTextDifficulty, difficult: boolean) {
  return [...new Set([category, lengthType, difficulty, difficult ? 'difficult' : undefined].filter(Boolean) as string[])];
}

export const practiceTexts: PracticeText[] = rawPracticeTexts.map((item) => {
  const lengthType = lengthTypeFor(item.reading, item.lengthType);
  const containsDifficultPatterns = hasDifficultRomanizationPattern(item.reading);
  const difficulty = difficultyFor(item.category, lengthType, containsDifficultPatterns);
  return {
    ...item,
    lengthType,
    difficulty,
    tags: tagsFor(item.category, lengthType, difficulty, containsDifficultPatterns),
    estimatedKeyCount: getPrimaryRomanization(item.reading).length,
    containsDifficultPatterns,
  };
});
